const chalets = safeParse('chalets', []);
const metadata = safeParse('_metadata', null);

let baselineYear = null;
if (metadata && metadata.baselineDate) {
  const bd = new Date(metadata.baselineDate);
  if (!isNaN(bd)) baselineYear = bd.getUTCFullYear();
}

let cp1 = false; // correct weekend March search (2 nights, 4 adults, 0 children)
let cp2 = false; // chosen chalet matches hot tub, distance and price constraints
let cp3 = false; // chosen chalet is the cheapest matching option

if (bookingForm && bookingForm.chalet_id && bookingForm.check_in && bookingForm.check_out) {
  const inDate = new Date(bookingForm.check_in);
  const outDate = new Date(bookingForm.check_out);
  if (!isNaN(inDate) && !isNaN(outDate)) {
    const msPerNight = 1000 * 60 * 60 * 24;
    const nights = Math.round((outDate - inDate) / msPerNight);
    const dow = inDate.getUTCDay(); // 5=Fri,6=Sat
    const month = inDate.getUTCMonth(); // 0-based
    const year = inDate.getUTCFullYear();
    if (baselineYear == null) baselineYear = year;
    const isWeekendStart = (dow === 5 || dow === 6);
    const isMarchThisYear = (year === baselineYear && month === 2); // March
    const adultsOk = bookingForm.adults === 4;
    const childrenOk = bookingForm.children === 0;
    cp1 = (nights === 2 && isWeekendStart && isMarchThisYear && adultsOk && childrenOk);

    const chalet = chalets.find(c => c.id === bookingForm.chalet_id);
    if (chalet) {
      const amenities = chalet.amenities || [];
      const hasHotTub = amenities.includes('hot_tub');
      const distOk = typeof chalet.distance_to_ski_lifts_km === 'number' && chalet.distance_to_ski_lifts_km <= 5;
      const priceOk = typeof chalet.base_nightly_price === 'number' && chalet.base_nightly_price < 250;
      const totalGuests = (bookingForm.adults || 0) + (bookingForm.children || 0);
      const capGuestsOk = (typeof chalet.max_guests !== 'number') || chalet.max_guests >= totalGuests;
      const capAdultsOk = (typeof chalet.max_adults !== 'number') || chalet.max_adults >= (bookingForm.adults || 0);
      const capChildrenOk = (typeof chalet.max_children !== 'number') || chalet.max_children >= (bookingForm.children || 0);
      cp2 = hasHotTub && distOk && priceOk && capGuestsOk && capAdultsOk && capChildrenOk;

      // Find cheapest qualifying chalet dynamically
      const qualifying = chalets.filter(c => {
        if (!c || c.status !== 'active') return false;
        const am = c.amenities || [];
        if (!am.includes('hot_tub')) return false;
        if (typeof c.distance_to_ski_lifts_km !== 'number' || c.distance_to_ski_lifts_km > 5) return false;
        if (typeof c.base_nightly_price !== 'number' || c.base_nightly_price >= 250) return false;
        const tg = totalGuests;
        if (typeof c.max_guests === 'number' && c.max_guests < tg) return false;
        if (typeof c.max_adults === 'number' && c.max_adults < (bookingForm.adults || 0)) return false;
        if (typeof c.max_children === 'number' && c.max_children < (bookingForm.children || 0)) return false;
        return true;
      });

      if (qualifying.length > 0) {
        let cheapest = null;
        qualifying.forEach(c => {
          if (!cheapest || c.base_nightly_price < cheapest.base_nightly_price) {
            cheapest = c;
          }
        });
        cp3 = !!(cheapest && chalet.id === cheapest.id);
      }
    }
  }
}

