    cp2 = hasSauna && petOk && bedroomsOk && priceOk && capGuestsOk && capAdultsOk && capChildrenOk;

    // Now compute cheapest matching chalet dynamically
    const targetAdults = 6;
    const targetChildren = 2;
    const targetGuests = targetAdults + targetChildren;

