  const lateOk = !!(lateCo && (lateCo.quantity || 0) === 1);
  cp1 = transferOk && breakfastOk && lateOk;

  const extrasTotal = extrasForBooking.reduce((sum, be) => sum + (be.total_price || 0), 0);
  const adults = booking.adults_count || 1;
  const perAdult = extrasTotal / adults;
  cp2 = extrasTotal > 0 && perAdult <= 150;

  const baseTotal = (booking.room_charges_total || 0) + (booking.taxes || 0) + (booking.fees || 0);
  const expectedGrand = baseTotal + extrasTotal;
  const extrasTotalStored = booking.extras_total != null ? booking.extras_total : 0;
  const grandOk = Math.abs((booking.grand_total || 0) - expectedGrand) < 0.01;
  const extrasStoredOk = Math.abs(extrasTotalStored - extrasTotal) < 0.01;
  const updatedAtOk = typeof booking.updated_at === 'string' && booking.updated_at.length > 0;
  cp3 = grandOk && extrasStoredOk && updatedAtOk;
}

checkpoints.push({ passed: cp1, weight: 0.4 });
checkpoints.push({ passed: cp2, weight: 0.3 });
checkpoints.push({ passed: cp3, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
